-- ── Zitadel ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Open-source, API-first identity and access management platform offering hosted login, multi-factor and passwordless authentication, and B2B multi-tenancy for developers.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$$0$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$St. Gallen, Switzerland, with a presence in San Francisco, California$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Zitadel Review 2026: Identity Platform Features and Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$See how Zitadel, the open-source identity and access management platform, compares on authentication, multi-tenancy, pricing plans, and developer APIs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Zitadel is an open-source, API-first identity and access management (IAM) platform that helps developers add authentication, authorization, and multi-tenant identity infrastructure to their applications. It is built by CAOS Ltd (also referred to as CAOS AG), a company founded on April 1, 2019, in St. Gallen, Switzerland, by Florian Forster, Fabienne Buhler, and a team of identity infrastructure specialists, with the company also maintaining a presence in San Francisco, California. Zitadel has raised outside funding, including a 2.5 million dollar seed round in June 2022 led by Nexus Venture Partners, and a 9 million dollar Series A round in November 2024 also led by Nexus Venture Partners with participation from Floodgate. Functionally, Zitadel positions itself as an all-in-one alternative to identity platforms like Auth0, Keycloak, and Firebase Authentication, aimed at applications serving consumers, businesses, and internal employees. Core capabilities include customizable hosted login pages, gRPC and REST APIs for embedding authentication directly into applications, and support for social logins, passwordless authentication, multi-factor authentication, and passkeys. Zitadel provides role-based access control for permission management, and its multi-tenancy model, built around organizations and projects, is designed specifically for B2B software that needs to isolate and manage many customer tenants within one system. A feature called ZITADEL Actions lets developers run custom logic after predefined identity events, such as login or registration, without deploying separate infrastructure, and the platform also supports service accounts for machine-to-machine identity. Zitadel holds OpenID certification and complies with ISO 27001, GDPR, and AICPA SOC 2 Type II standards, reflecting its focus on regulated and enterprise use cases. The project has an active open-source community, with roughly 4,000 GitHub stars, more than 2,500 Discord members, and over 50 contributors, and reports usage across 69 countries. Zitadel can be deployed as a fully managed cloud service or self-hosted, and it offers a free tier that includes unlimited organizations and users, up to 100 daily active users, three identity providers, and custom workflows. Paid plans scale up from there: the Pro plan is priced at 100 dollars per month and includes up to 25,000 daily active users, custom domains, and a defined uptime guarantee with response-time service objectives, while the Enterprise plan is custom-priced and offers unlimited daily active users, a dedicated technical account manager, custom support SLAs, a commercial license, and the choice of cloud or self-hosted infrastructure.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '69d914d3-8667-4dc1-83ca-010c75550ec9';

