-- ── ZNC ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Free, open-source IRC bouncer written in C++ that keeps a persistent connection to IRC networks, supporting multiple clients, playback buffers, and modules.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2004, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$ZNC Review 2026: Open-Source IRC Bouncer Features and Setup$q$, seo_title),
  seo_meta_description = COALESCE($q$Learn what ZNC, the free open-source IRC bouncer, offers: persistent connections, multi-client support, modules, SSL, and how to self-host it.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$ZNC is a free, open-source IRC bouncer, a self-hosted background service that maintains a persistent connection to IRC networks on a user's behalf so they never lose their place in a channel or their nickname when their own client disconnects. Written in C++, the project's first commit dates to July 2004, and it has been maintained continuously since, moving its home from SourceForge to GitHub around February 2011. ZNC is released under the Apache License 2.0, meaning it is completely free to download, self-host, and modify, with no commercial edition or paid tier. Functionally, ZNC sits between an IRC client and an IRC network. It stays connected to configured networks and channels at all times, buffering messages so that when a user's client reconnects, whether from a phone, laptop, or another device, they can catch up on everything they missed through a per-channel playback buffer. Multiple client connections from different locations can attach to the same ZNC account simultaneously, all appearing under the same nickname on IRC, which is useful for people who move between devices throughout the day. Beyond core bouncing, ZNC includes a built-in web interface for configuration, support for multiple user accounts on a single ZNC instance, transparent DCC (direct client-to-client) bouncing for file transfers, and native support for SSL/TLS encrypted connections when the host system has OpenSSL installed, as well as IPv6 connectivity. ZNC's functionality can be extended through a module system; modules can be written in C++, Python, Perl, or Tcl, and the community has built modules for features like push notifications to mobile IRC clients, logging, and network-specific quality-of-life improvements. Because it is entirely self-hosted, ZNC is typically run on a always-on server or virtual private server by technically inclined users, IRC network operators, and open-source community members who want reliable, persistent IRC presence without relying on a commercial service. As a community-maintained open-source project rather than a company, ZNC has no headquarters, employee count, or subscription pricing; it is distributed through its official repository on GitHub and via package managers on most Linux distributions and BSD systems.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '1f9434f4-e927-45b2-a88a-bd4e32807373';

