INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0302fe96-81fa-4f14-b5ac-8414fede5b87', $q$Intake-to-procure$q$, $q$A single front door for employees to submit purchase requests, routed through configurable, no-code approval workflows.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0302fe96-81fa-4f14-b5ac-8414fede5b87', $q$Procure-to-pay automation$q$, $q$Automates purchase order creation and invoice processing to speed up closing cycles.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0302fe96-81fa-4f14-b5ac-8414fede5b87', $q$Sourcing and RFx management$q$, $q$Streamlines competitive vendor sourcing with AI-assisted decision support.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0302fe96-81fa-4f14-b5ac-8414fede5b87', $q$Global payments$q$, $q$Enables compliant, accurate cross-border vendor payments.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0302fe96-81fa-4f14-b5ac-8414fede5b87', $q$Vendor spend cards$q$, $q$Provides real-time visibility and spend controls tied to individual vendors.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0302fe96-81fa-4f14-b5ac-8414fede5b87', $q$AI Superagents$q$, $q$Governed AI agents that automate repetitive procurement tasks such as document review and policy checks.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0302fe96-81fa-4f14-b5ac-8414fede5b87', $q$Risk and policy controls$q$, $q$Enforces spend policy and compliance checks throughout the purchasing lifecycle.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0302fe96-81fa-4f14-b5ac-8414fede5b87', $q$ERP and finance integrations$q$, $q$Connects with existing ERP, accounting, and procure-to-pay systems rather than replacing them.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0302fe96-81fa-4f14-b5ac-8414fede5b87', $q$Consolidates intake, approvals, sourcing, and payments into one orchestration layer$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0302fe96-81fa-4f14-b5ac-8414fede5b87', $q$No-code workflow builder makes it easy to configure cross-functional approval paths$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0302fe96-81fa-4f14-b5ac-8414fede5b87', $q$Strong enterprise customer base with documented ROI and cycle-time improvements$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0302fe96-81fa-4f14-b5ac-8414fede5b87', $q$AI Superagents automate repetitive procurement busywork while keeping humans in the loop$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0302fe96-81fa-4f14-b5ac-8414fede5b87', $q$Integrates with existing ERP and finance systems instead of forcing a rip-and-replace$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0302fe96-81fa-4f14-b5ac-8414fede5b87', $q$No public pricing, making it hard to budget without a sales conversation$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0302fe96-81fa-4f14-b5ac-8414fede5b87', $q$Primarily built for mid-market and enterprise procurement teams, so it may be more than small businesses need$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0302fe96-81fa-4f14-b5ac-8414fede5b87', $q$Advanced modules like CLM and analytics cost extra on top of the base platform$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0302fe96-81fa-4f14-b5ac-8414fede5b87', $q$Implementation and workflow configuration can require dedicated procurement or IT involvement$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0302fe96-81fa-4f14-b5ac-8414fede5b87', $q$What does Zip do?$q$, $q$Zip is an AI procurement orchestration platform that manages the entire purchasing process, from an employee submitting a request through approval, sourcing, purchase orders, invoicing, and payment.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0302fe96-81fa-4f14-b5ac-8414fede5b87', $q$How much does Zip cost?$q$, $q$Zip does not publish public pricing. Costs are quote-based, typically combining a platform fee with per-seat pricing and optional add-on modules.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0302fe96-81fa-4f14-b5ac-8414fede5b87', $q$Is Zip the same company as ziphq.com?$q$, $q$Yes. Zip was originally known by the domain ziphq.com and now operates primarily at zip.com.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0302fe96-81fa-4f14-b5ac-8414fede5b87', $q$Who uses Zip?$q$, $q$Zip is used by procurement, finance, IT, security, and legal teams at more than 1,000 organizations, including Snowflake, Northwestern Mutual, Miro, and Patreon.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0302fe96-81fa-4f14-b5ac-8414fede5b87', $q$Does Zip replace an ERP system?$q$, $q$No. Zip is designed to integrate with and orchestrate on top of existing ERP and financial systems rather than replace them.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0302fe96-81fa-4f14-b5ac-8414fede5b87', $q$What are AI Superagents in Zip?$q$, $q$AI Superagents are governed AI agents within Zip that automate repetitive procurement tasks such as document collection and policy checks, with human oversight built in.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0302fe96-81fa-4f14-b5ac-8414fede5b87', $q$Who founded Zip?$q$, $q$Zip was co-founded in 2020 by Rujul Zaparde, Lu Cheng, and Felix Meng.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0302fe96-81fa-4f14-b5ac-8414fede5b87', $q$What size companies is Zip built for?$q$, $q$Zip serves startups, mid-market companies, and enterprises, though its feature depth and pricing model are most commonly adopted by mid-market and larger organizations.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0302fe96-81fa-4f14-b5ac-8414fede5b87', $q$Procurement request intake$q$, $q$Giving every employee a standardized way to submit purchase and vendor requests instead of scattered emails and spreadsheets.$q$, $q$Procurement and operations teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0302fe96-81fa-4f14-b5ac-8414fede5b87', $q$Cross-functional purchase approvals$q$, $q$Routing spend requests automatically through finance, legal, security, and IT reviewers based on configurable rules.$q$, $q$Finance and legal teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0302fe96-81fa-4f14-b5ac-8414fede5b87', $q$Vendor sourcing and contract orchestration$q$, $q$Running RFx processes and managing supplier onboarding and contracts within one connected workflow.$q$, $q$Enterprise procurement and sourcing teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0302fe96-81fa-4f14-b5ac-8414fede5b87', $q$Custom$q$, $q$Custom quote$q$, $q$annual$q$, NULL, $q$["Platform access fee","Per-seat pricing for requesters, approvers, and procurement staff","Optional add-on modules such as contract lifecycle management and advanced analytics","ERP and finance system integrations"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0302fe96-81fa-4f14-b5ac-8414fede5b87', $q$overview$q$, $q$What Is Zip$q$, 2, ARRAY[$q$Zip is an AI-powered procurement orchestration platform built to give organizations a single, unified system for managing every purchase request from the moment it is submitted through final payment. Rather than replacing a company's existing ERP or finance stack, Zip sits on top of it, coordinating requesters, approvers, procurement teams, and finance and legal stakeholders through configurable workflows.$q$, $q$Founded in 2020 by Rujul Zaparde, Lu Cheng, and Felix Meng, Zip grew quickly by focusing on the messy, manual parts of enterprise procurement, especially the intake and approval stage where requests often get lost in email threads and spreadsheets. The company is headquartered in San Francisco and is backed by investors including Bond, DST Global, and Y Combinator.$q$, $q$Today Zip is used by more than 1,000 organizations, including well-known names like Snowflake, Northwestern Mutual, Miro, and Patreon, spanning industries such as technology, financial services, and life sciences.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0302fe96-81fa-4f14-b5ac-8414fede5b87', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Zip's foundational feature is intake-to-procure: a single front door where any employee can submit a purchase or vendor request, which is then automatically routed through no-code, cross-functional approval workflows based on spend amount, department, or risk profile.$q$, $q$On top of intake, Zip offers procure-to-pay automation for purchase orders and invoices, sourcing and RFx tools for running competitive vendor selection, global payment processing for compliant cross-border transactions, and vendor cards that give finance real-time visibility and spend controls at the point of purchase.$q$, $q$The platform's AI Superagents extend automation further by handling repetitive procurement tasks such as document collection, policy checks, and contract review under human governance, while spend analytics and integrations with ERP and financial systems keep procurement data connected to the rest of the business.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0302fe96-81fa-4f14-b5ac-8414fede5b87', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Zip does not publish standard list pricing on its website. Instead, pricing is quote-based and depends on company size, number of seats, transaction volume, and which modules an organization selects.$q$, $q$The typical structure combines a platform access fee with per-seat pricing for requesters, approvers, and procurement staff, while advanced modules like contract lifecycle management and advanced analytics are usually priced as add-ons.$q$, $q$Most Zip contracts run on annual terms, and organizations that commit to multi-year agreements or larger user counts commonly negotiate discounted rates below list price.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b18b84bf-1a80-44d2-8619-43e15614d140', $q$Distributed trace collection$q$, $q$Gathers timing data as requests travel across multiple microservices.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b18b84bf-1a80-44d2-8619-43e15614d140', $q$Trace lookup and search$q$, $q$Find traces by ID or filter by service name, operation, tags, and duration.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b18b84bf-1a80-44d2-8619-43e15614d140', $q$Dependency diagrams$q$, $q$Visualizes how services call one another to reveal bottlenecks and deprecated paths.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b18b84bf-1a80-44d2-8619-43e15614d140', $q$Multiple transport options$q$, $q$Supports HTTP, Kafka, Apache ActiveMQ, gRPC, and RabbitMQ for sending trace data.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b18b84bf-1a80-44d2-8619-43e15614d140', $q$Pluggable storage backends$q$, $q$Stores traces in memory or in production-grade systems like Cassandra or Elasticsearch.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b18b84bf-1a80-44d2-8619-43e15614d140', $q$Performance summaries$q$, $q$Automatically calculates per-service time spent and operation failure rates.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b18b84bf-1a80-44d2-8619-43e15614d140', $q$Open governance$q$, $q$Maintained by the OpenZipkin community organization on GitHub.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b18b84bf-1a80-44d2-8619-43e15614d140', $q$Apache 2.0 licensing$q$, $q$Free to self-host, modify, and use commercially without licensing fees.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b18b84bf-1a80-44d2-8619-43e15614d140', $q$Completely free and open source with no vendor lock-in$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b18b84bf-1a80-44d2-8619-43e15614d140', $q$Mature project with a long track record dating back to 2012$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b18b84bf-1a80-44d2-8619-43e15614d140', $q$Flexible transport and storage backend options for different scales$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b18b84bf-1a80-44d2-8619-43e15614d140', $q$Useful dependency diagrams for understanding complex microservice call chains$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b18b84bf-1a80-44d2-8619-43e15614d140', $q$Active OpenZipkin community and GitHub repository$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b18b84bf-1a80-44d2-8619-43e15614d140', $q$Requires manual instrumentation of applications with a compatible tracer$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b18b84bf-1a80-44d2-8619-43e15614d140', $q$No official commercial support or SLA, unlike managed observability vendors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b18b84bf-1a80-44d2-8619-43e15614d140', $q$Operating storage backends like Cassandra or Elasticsearch adds infrastructure overhead$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b18b84bf-1a80-44d2-8619-43e15614d140', $q$UI and feature set are more basic than some newer commercial tracing tools$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b18b84bf-1a80-44d2-8619-43e15614d140', $q$What is Zipkin used for?$q$, $q$Zipkin is used to trace requests as they move across microservices, helping engineers diagnose latency and failure points in distributed systems.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b18b84bf-1a80-44d2-8619-43e15614d140', $q$Is Zipkin free?$q$, $q$Yes. Zipkin is open source and released under the Apache License 2.0, with no cost to download, self-host, or modify.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b18b84bf-1a80-44d2-8619-43e15614d140', $q$Who created Zipkin?$q$, $q$Zipkin was created by Twitter engineers in 2012 and has been maintained by the independent OpenZipkin community since 2015.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b18b84bf-1a80-44d2-8619-43e15614d140', $q$How does Zipkin collect trace data?$q$, $q$Applications are instrumented with a tracer library, then send trace data to Zipkin over HTTP, Kafka, Apache ActiveMQ, gRPC, or RabbitMQ.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b18b84bf-1a80-44d2-8619-43e15614d140', $q$What storage backends does Zipkin support?$q$, $q$Zipkin can store traces in memory for testing, or in production backends such as Apache Cassandra or Elasticsearch.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b18b84bf-1a80-44d2-8619-43e15614d140', $q$How is Zipkin different from Jaeger?$q$, $q$Both are open-source distributed tracing systems; Zipkin predates Jaeger and originated at Twitter, while Jaeger was created at Uber, with each having its own storage and UI implementation.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b18b84bf-1a80-44d2-8619-43e15614d140', $q$Does Zipkin offer a hosted or managed version?$q$, $q$Zipkin itself is a self-hosted open-source project without an official managed cloud offering.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b18b84bf-1a80-44d2-8619-43e15614d140', $q$Can Zipkin work with OpenTelemetry?$q$, $q$Yes, many OpenTelemetry-compatible instrumentation libraries can export trace data to a Zipkin backend.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b18b84bf-1a80-44d2-8619-43e15614d140', $q$Microservice latency troubleshooting$q$, $q$Tracing individual requests across services to find the source of slow response times.$q$, $q$Backend and platform engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b18b84bf-1a80-44d2-8619-43e15614d140', $q$Service dependency mapping$q$, $q$Visualizing how services call each other to understand architecture and identify deprecated paths.$q$, $q$DevOps and site reliability engineers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b18b84bf-1a80-44d2-8619-43e15614d140', $q$Error and failure rate analysis$q$, $q$Identifying which services or operations have elevated failure rates using trace summaries.$q$, $q$Engineering teams running production microservices$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b18b84bf-1a80-44d2-8619-43e15614d140', $q$Open Source$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Self-hosted distributed tracing","Trace lookup and search","Dependency diagrams","Support for HTTP, Kafka, ActiveMQ, gRPC, and RabbitMQ transports","In-memory, Cassandra, or Elasticsearch storage"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b18b84bf-1a80-44d2-8619-43e15614d140', $q$overview$q$, $q$What Is Zipkin$q$, 2, ARRAY[$q$Zipkin is an open-source distributed tracing system that helps engineering teams troubleshoot latency problems in microservice architectures by collecting timing data as requests move across services.$q$, $q$The project originated at Twitter in 2012, where engineers built it to diagnose performance issues in the company's rapidly scaling service infrastructure. In mid-2015, the project moved from Twitter to OpenZipkin, an independent community organization that maintains it on GitHub today.$q$, $q$Zipkin is released under the Apache License 2.0, so it can be self-hosted, modified, and used commercially free of charge.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b18b84bf-1a80-44d2-8619-43e15614d140', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Applications send trace data to Zipkin after being instrumented with a compatible tracer or client library. Zipkin supports multiple transport options for receiving this data, including HTTP, Kafka, Apache ActiveMQ, gRPC, and RabbitMQ, and can store traces in memory or in production backends such as Apache Cassandra or Elasticsearch.$q$, $q$The Zipkin UI allows engineers to search traces by trace ID or by filtering on service name, operation name, tags, and duration, making it possible to quickly isolate a slow or failing request.$q$, $q$Zipkin automatically summarizes key performance data, such as the percentage of time spent per service and operation failure rates, and generates dependency diagrams that visualize how requests flow through an application, helping teams identify bottlenecks and deprecated service paths.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b18b84bf-1a80-44d2-8619-43e15614d140', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Zipkin is completely free and open source under the Apache License 2.0. There are no paid tiers, subscriptions, or official commercial editions.$q$, $q$Costs are limited to the infrastructure a team chooses for hosting Zipkin's collector and storage backend, such as servers running Cassandra or Elasticsearch.$q$, $q$Support is community-driven through GitHub issues and community chat channels rather than a paid support contract.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b18b84bf-1a80-44d2-8619-43e15614d140', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69d914d3-8667-4dc1-83ca-010c75550ec9', $q$Hosted login pages$q$, $q$Customizable, ready-made login screens that can be branded to match an application.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69d914d3-8667-4dc1-83ca-010c75550ec9', $q$gRPC and REST APIs$q$, $q$Programmatic access for embedding authentication directly into custom application flows.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69d914d3-8667-4dc1-83ca-010c75550ec9', $q$Passwordless and passkey authentication$q$, $q$Supports modern authentication methods alongside traditional passwords and multi-factor authentication.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69d914d3-8667-4dc1-83ca-010c75550ec9', $q$Role-based access control$q$, $q$Manages user and service permissions across applications and organizations.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69d914d3-8667-4dc1-83ca-010c75550ec9', $q$B2B multi-tenancy$q$, $q$Organization and project structures designed to isolate and manage many customer tenants.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69d914d3-8667-4dc1-83ca-010c75550ec9', $q$ZITADEL Actions$q$, $q$Runs custom code after identity events like login or registration without extra infrastructure.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69d914d3-8667-4dc1-83ca-010c75550ec9', $q$Service accounts$q$, $q$Identity management for machine-to-machine and automated workloads.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69d914d3-8667-4dc1-83ca-010c75550ec9', $q$Compliance certifications$q$, $q$OpenID certified with ISO 27001, GDPR, and SOC 2 Type II compliance.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('69d914d3-8667-4dc1-83ca-010c75550ec9', $q$Open source with the option to self-host for full data control$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('69d914d3-8667-4dc1-83ca-010c75550ec9', $q$Strong compliance posture, including SOC 2 Type II and ISO 27001$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('69d914d3-8667-4dc1-83ca-010c75550ec9', $q$Generous free tier for smaller projects and early-stage products$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('69d914d3-8667-4dc1-83ca-010c75550ec9', $q$Purpose-built multi-tenancy for B2B SaaS applications$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('69d914d3-8667-4dc1-83ca-010c75550ec9', $q$Modern authentication support, including passkeys and passwordless login$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('69d914d3-8667-4dc1-83ca-010c75550ec9', $q$Pro plan daily active user limits may be restrictive for fast-growing consumer apps$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('69d914d3-8667-4dc1-83ca-010c75550ec9', $q$Enterprise pricing is custom and not published, requiring a sales conversation$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('69d914d3-8667-4dc1-83ca-010c75550ec9', $q$Self-hosting requires infrastructure and operational expertise$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('69d914d3-8667-4dc1-83ca-010c75550ec9', $q$Smaller ecosystem and community size compared to larger identity providers like Auth0$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69d914d3-8667-4dc1-83ca-010c75550ec9', $q$What is Zitadel used for?$q$, $q$Zitadel is used to add authentication, authorization, and multi-tenant identity management to applications through hosted login pages and developer APIs.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69d914d3-8667-4dc1-83ca-010c75550ec9', $q$Is Zitadel open source?$q$, $q$Yes, Zitadel is open source and can be self-hosted, in addition to being offered as a managed cloud service.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69d914d3-8667-4dc1-83ca-010c75550ec9', $q$How much does Zitadel cost?$q$, $q$Zitadel has a free plan for up to 100 daily active users, a Pro plan at 100 dollars per month for up to 25,000 daily active users, and a custom-priced Enterprise plan.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69d914d3-8667-4dc1-83ca-010c75550ec9', $q$Who makes Zitadel?$q$, $q$Zitadel is developed by CAOS Ltd, a company founded in 2019 in St. Gallen, Switzerland, with an additional office in San Francisco.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69d914d3-8667-4dc1-83ca-010c75550ec9', $q$What authentication methods does Zitadel support?$q$, $q$Zitadel supports passwords, social logins, multi-factor authentication, passwordless login, and passkeys.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69d914d3-8667-4dc1-83ca-010c75550ec9', $q$Is Zitadel suitable for B2B SaaS applications?$q$, $q$Yes, Zitadel's organization and project structure is specifically designed to support multi-tenant B2B applications.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69d914d3-8667-4dc1-83ca-010c75550ec9', $q$What compliance certifications does Zitadel have?$q$, $q$Zitadel is OpenID certified and complies with ISO 27001, GDPR, and AICPA SOC 2 Type II standards.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69d914d3-8667-4dc1-83ca-010c75550ec9', $q$Can Zitadel be self-hosted?$q$, $q$Yes, in addition to its managed cloud offering, Zitadel can be deployed and run entirely on an organization's own infrastructure.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('69d914d3-8667-4dc1-83ca-010c75550ec9', $q$Customer authentication for SaaS applications$q$, $q$Adding secure login, multi-factor authentication, and passwordless options to a product without building identity infrastructure in-house.$q$, $q$Software development teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('69d914d3-8667-4dc1-83ca-010c75550ec9', $q$B2B multi-tenant identity management$q$, $q$Managing separate organizations, projects, and permission structures for many business customers within one platform.$q$, $q$B2B SaaS companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('69d914d3-8667-4dc1-83ca-010c75550ec9', $q$Regulated and enterprise identity infrastructure$q$, $q$Meeting compliance requirements such as GDPR, ISO 27001, and SOC 2 while controlling data residency through self-hosting or regional cloud options.$q$, $q$Enterprises and regulated industries$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('69d914d3-8667-4dc1-83ca-010c75550ec9', $q$Free$q$, $q$$0$q$, $q$monthly$q$, NULL, $q$["Up to 100 daily active users","Unlimited organizations and users","Three identity providers","Custom workflows","Data residency options in EU, US, Switzerland, and Australia"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('69d914d3-8667-4dc1-83ca-010c75550ec9', $q$Pro$q$, $q$$100$q$, $q$monthly$q$, NULL, $q$["Up to 25,000 daily active users","Custom domain support","Defined uptime guarantee","One-hour response service level objective"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('69d914d3-8667-4dc1-83ca-010c75550ec9', $q$Enterprise$q$, $q$Custom quote$q$, $q$custom$q$, NULL, $q$["Unlimited daily active users","Cloud or self-hosted deployment","Dedicated technical account manager","Custom support SLA","Commercial license"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('69d914d3-8667-4dc1-83ca-010c75550ec9', $q$overview$q$, $q$What Is Zitadel$q$, 2, ARRAY[$q$Zitadel is an open-source, API-first identity and access management platform that gives developers a way to add login, authentication, and multi-tenant identity infrastructure to their applications without building it from scratch.$q$, $q$The platform is developed by CAOS Ltd, a company founded in 2019 in St. Gallen, Switzerland, with an additional presence in San Francisco, California. Zitadel is positioned as an open-source alternative to identity platforms such as Auth0, Keycloak, and Firebase Authentication.$q$, $q$It can be run as a fully managed cloud service or self-hosted, giving teams flexibility over data residency and infrastructure control while retaining access to the same feature set.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('69d914d3-8667-4dc1-83ca-010c75550ec9', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Zitadel provides customizable hosted login pages along with gRPC and REST APIs, so developers can either use Zitadel's own login flow or build fully custom authentication experiences on top of its backend.$q$, $q$Authentication options include social logins, passwordless authentication, multi-factor authentication, and passkeys, while role-based access control governs what authenticated users and services are allowed to do within an application.$q$, $q$Its multi-tenancy model, built around organizations and projects, is designed for B2B software serving many customer tenants, and ZITADEL Actions let developers trigger custom logic after identity events like login or registration without deploying extra infrastructure. Service accounts are also supported for machine and workload identities.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('69d914d3-8667-4dc1-83ca-010c75550ec9', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Zitadel offers a free plan with unlimited organizations and users, up to 100 daily active users, three identity providers, and custom workflows, making it viable for small projects and testing.$q$, $q$The Pro plan costs 100 dollars per month and raises the limit to 25,000 daily active users, adds custom domain support, and includes a defined uptime guarantee with a one-hour response service level objective.$q$, $q$The Enterprise plan is custom-priced and includes unlimited daily active users, a dedicated technical account manager, custom support SLAs, a commercial license, and the choice between cloud-hosted or self-hosted deployment.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('69d914d3-8667-4dc1-83ca-010c75550ec9', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f9434f4-e927-45b2-a88a-bd4e32807373', $q$Persistent IRC connection$q$, $q$Stays connected to IRC networks and channels even when a user's own client disconnects.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f9434f4-e927-45b2-a88a-bd4e32807373', $q$Per-channel playback buffer$q$, $q$Lets reconnecting clients catch up on messages missed while offline.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f9434f4-e927-45b2-a88a-bd4e32807373', $q$Multi-client support$q$, $q$Multiple devices can connect to the same ZNC account and appear under one nickname.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f9434f4-e927-45b2-a88a-bd4e32807373', $q$Built-in web interface$q$, $q$Provides browser-based configuration for users and administrators.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f9434f4-e927-45b2-a88a-bd4e32807373', $q$Module system$q$, $q$Extends functionality using modules written in C++, Python, Perl, or Tcl.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f9434f4-e927-45b2-a88a-bd4e32807373', $q$SSL and IPv6 support$q$, $q$Supports encrypted connections and modern networking out of the box.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f9434f4-e927-45b2-a88a-bd4e32807373', $q$Transparent DCC bouncing$q$, $q$Handles direct client-to-client file transfers through the bouncer.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f9434f4-e927-45b2-a88a-bd4e32807373', $q$Multi-user hosting$q$, $q$A single ZNC instance can serve multiple separate user accounts.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1f9434f4-e927-45b2-a88a-bd4e32807373', $q$Completely free and open source with no licensing costs$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1f9434f4-e927-45b2-a88a-bd4e32807373', $q$Mature, stable project with two decades of active development$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1f9434f4-e927-45b2-a88a-bd4e32807373', $q$Extensible module system supports several programming languages$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1f9434f4-e927-45b2-a88a-bd4e32807373', $q$Lets multiple devices share one persistent IRC presence$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1f9434f4-e927-45b2-a88a-bd4e32807373', $q$Lightweight enough to run on a small self-hosted server$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1f9434f4-e927-45b2-a88a-bd4e32807373', $q$Requires self-hosting and basic server administration skills$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1f9434f4-e927-45b2-a88a-bd4e32807373', $q$No official managed or hosted version$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1f9434f4-e927-45b2-a88a-bd4e32807373', $q$Configuration and module setup can be technical for non-developers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1f9434f4-e927-45b2-a88a-bd4e32807373', $q$Built specifically for IRC, so it has no relevance outside that protocol$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1f9434f4-e927-45b2-a88a-bd4e32807373', $q$What is ZNC used for?$q$, $q$ZNC is used as an IRC bouncer, keeping a persistent connection to IRC networks so a user stays connected and can reconnect from multiple devices without losing channel history.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1f9434f4-e927-45b2-a88a-bd4e32807373', $q$Is ZNC free?$q$, $q$Yes, ZNC is completely free and open source under the Apache License 2.0.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1f9434f4-e927-45b2-a88a-bd4e32807373', $q$Do I need to self-host ZNC?$q$, $q$Yes, ZNC is a self-hosted application typically run on an always-on server or virtual private server.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1f9434f4-e927-45b2-a88a-bd4e32807373', $q$Can multiple people use one ZNC installation?$q$, $q$Yes, a single ZNC instance supports multiple separate user accounts, each with its own configuration.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1f9434f4-e927-45b2-a88a-bd4e32807373', $q$What programming languages can extend ZNC?$q$, $q$ZNC modules can be written in C++, Python, Perl, or Tcl.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1f9434f4-e927-45b2-a88a-bd4e32807373', $q$Does ZNC support encrypted connections?$q$, $q$Yes, ZNC automatically supports SSL/TLS connections when the host system has OpenSSL installed, along with IPv6.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1f9434f4-e927-45b2-a88a-bd4e32807373', $q$How long has ZNC been around?$q$, $q$ZNC's first commit dates back to July 2004, making it one of the longest-running IRC bouncer projects still actively maintained.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1f9434f4-e927-45b2-a88a-bd4e32807373', $q$Does ZNC have a web interface?$q$, $q$Yes, ZNC includes a built-in web interface for configuration and administration.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1f9434f4-e927-45b2-a88a-bd4e32807373', $q$Persistent IRC presence$q$, $q$Staying connected to IRC channels around the clock even when a personal device or client is offline.$q$, $q$Open-source contributors and IRC community members$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1f9434f4-e927-45b2-a88a-bd4e32807373', $q$Multi-device IRC access$q$, $q$Connecting to the same IRC identity from a phone, laptop, and desktop without losing message history.$q$, $q$Developers and system administrators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1f9434f4-e927-45b2-a88a-bd4e32807373', $q$Self-hosted messaging infrastructure$q$, $q$Running a lightweight, self-controlled bouncer service for a team or community instead of relying on a third-party host.$q$, $q$Self-hosting enthusiasts and IRC network operators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1f9434f4-e927-45b2-a88a-bd4e32807373', $q$Open Source$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Self-hosted IRC bouncer","Persistent connection with playback buffer","Multi-client and multi-user support","Module extensibility","SSL and IPv6 support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1f9434f4-e927-45b2-a88a-bd4e32807373', $q$overview$q$, $q$What Is ZNC$q$, 2, ARRAY[$q$ZNC is a free, open-source IRC bouncer that maintains a persistent connection to IRC networks so users never lose their place in a conversation or their nickname, even when their own client goes offline.$q$, $q$Written in C++, the project's history dates back to its first commit in July 2004, and it has remained an actively maintained open-source project since, now hosted on GitHub under the znc/znc repository.$q$, $q$ZNC is released under the Apache License 2.0, making it free to download, self-host, and modify with no commercial licensing fees.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1f9434f4-e927-45b2-a88a-bd4e32807373', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$ZNC stays connected to configured IRC networks and channels at all times, buffering messages per channel so that when a user's client reconnects, they can replay everything they missed while disconnected.$q$, $q$Multiple client connections, from a phone, laptop, or desktop, can attach to the same ZNC account simultaneously and appear as one continuous presence on IRC under the same nickname.$q$, $q$The tool includes a built-in web interface, support for multiple user accounts on one instance, transparent DCC bouncing for file transfers, and native SSL/TLS and IPv6 support. Its functionality can be extended with modules written in C++, Python, Perl, or Tcl, including community modules for push notifications and logging.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1f9434f4-e927-45b2-a88a-bd4e32807373', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$ZNC is entirely free and open source under the Apache License 2.0, with no paid tiers or commercial edition.$q$, $q$The only cost associated with running ZNC is the infrastructure needed to host it, typically an always-on server or virtual private server.$q$, $q$Support comes from the open-source community through GitHub, the project wiki, and IRC channels rather than a paid support plan.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1f9434f4-e927-45b2-a88a-bd4e32807373', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1f9434f4-e927-45b2-a88a-bd4e32807373', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
