INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('970dd292-16fa-475f-996d-e50070df18a1', $q$Is Zoho Books free?$q$, $q$Yes, Zoho Books offers a free plan for one user plus an accountant with core invoicing, quotes, expenses, and reporting features.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('970dd292-16fa-475f-996d-e50070df18a1', $q$How much does Zoho Books cost?$q$, $q$Paid plans range from 12 dollars per month for Standard up to 249 dollars per month for Ultimate, with lower rates available when billed annually.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('970dd292-16fa-475f-996d-e50070df18a1', $q$Does Zoho Books support inventory management?$q$, $q$Yes, starting with the Professional plan, Zoho Books supports inventory tracking, and Elite adds advanced inventory and warehouse management.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('970dd292-16fa-475f-996d-e50070df18a1', $q$Can Zoho Books integrate with other Zoho apps?$q$, $q$Yes, Zoho Books connects with other Zoho products such as Zoho CRM, Zoho Inventory, and Zoho Payroll for a connected back office.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('970dd292-16fa-475f-996d-e50070df18a1', $q$Does Zoho Books support multiple currencies?$q$, $q$Yes, multi-currency support is available starting with the Professional plan.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('970dd292-16fa-475f-996d-e50070df18a1', $q$Is Zoho Books suitable for accounting firms?$q$, $q$Yes, accounting firms can use Zoho Books to manage client books, and the free plan includes an accountant user by default.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('970dd292-16fa-475f-996d-e50070df18a1', $q$What reporting does Zoho Books include?$q$, $q$Zoho Books includes over 50 reports on the free plan, plus advanced analytics and KPI tracking on the Ultimate plan.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('970dd292-16fa-475f-996d-e50070df18a1', $q$Is there a mobile app for Zoho Books?$q$, $q$Yes, Zoho Books is available on iOS, Android, and Windows desktop, in addition to the web application.$q$, 7, 'published');
