INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('970dd292-16fa-475f-996d-e50070df18a1', $q$Elite$q$, $q$$129/month ($100/month billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["10 users","Advanced inventory","Warehouse management","Shopify integration for up to 2 stores"]$q$::jsonb, 4);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('970dd292-16fa-475f-996d-e50070df18a1', $q$Ultimate$q$, $q$$249/month ($200/month billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["15 users","Advanced analytics","50+ pre-built visualizations","KPI tracking","Up to 3 million records"]$q$::jsonb, 5);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('970dd292-16fa-475f-996d-e50070df18a1', $q$overview$q$, $q$What Is Zoho Books$q$, 2, ARRAY[$q$Zoho Books is cloud-based accounting software designed to help small businesses and growing companies manage invoicing, expenses, inventory, banking, and financial reporting from one platform.$q$, $q$First introduced in 2011, Zoho Books is part of the wider Zoho Corporation suite of business applications. Zoho itself was founded in 1996 and is headquartered in Chennai, India, with a US headquarters in Austin, Texas, and roughly 24,000 employees globally.$q$, $q$Zoho Books can be used as a standalone accounting tool or combined with other Zoho products, such as Zoho CRM and Zoho Inventory, for businesses that want a connected back office.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('970dd292-16fa-475f-996d-e50070df18a1', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform covers the core accounting workflow: creating quotes and invoices with automated payment reminders and multiple payment options, tracking vendor bills and recurring expenses, and reconciling bank transactions through connected bank feeds.$q$, $q$Inventory tracking lets businesses monitor stock levels, set reorder points, and automatically update quantities as purchases and sales occur, while project features allow time logging and billing for hours or resources used.$q$, $q$Financial reporting includes profit and loss statements, cash flow reports, and tax insights, and the Zia AI assistant helps flag transaction anomalies and automate collections. Zoho Books is available on web, iOS, Android, and Windows, with support for custom templates, fields, and reports.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('970dd292-16fa-475f-996d-e50070df18a1', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Zoho Books offers a free plan for one user plus an accountant, covering invoicing, quotes, expenses, receipt autoscans, and more than 50 reports.$q$, $q$Paid monthly plans range from Standard at 12 dollars per month up to Ultimate at 249 dollars per month, adding users and capabilities like multi-currency support, inventory management, revenue recognition, cash flow forecasting, and advanced analytics as tiers increase.$q$, $q$Billing annually discounts every paid plan by roughly 17 to 25 percent, and add-ons such as extra users, document autoscans, additional business locations, and expense claims are available for further customization.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca9138f2-35fd-49cf-8af2-819fa2691854', $q$Sales workflow automation$q$, $q$No-code workflows and cadence management to automate repetitive sales tasks.$q$, 0);
