INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ca9138f2-35fd-49cf-8af2-819fa2691854', $q$Is Zoho CRM free?$q$, $q$Yes, Zoho CRM offers a free edition for up to three users with essential lead management and mobile app features.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ca9138f2-35fd-49cf-8af2-819fa2691854', $q$How much does Zoho CRM cost?$q$, $q$Paid plans billed annually range from roughly 14 dollars per user per month for Standard up to roughly 52 dollars per user per month for Ultimate.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ca9138f2-35fd-49cf-8af2-819fa2691854', $q$Does Zoho CRM include AI features?$q$, $q$Yes, Zoho CRM includes Zia, Zoho's built-in AI assistant, plus direct ChatGPT integration for additional AI-assisted tasks.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ca9138f2-35fd-49cf-8af2-819fa2691854', $q$What is the difference between Zoho CRM plans?$q$, $q$Plans differ mainly in automation depth and AI access: Standard covers core sales tools, Professional adds CPQ and inventory, Enterprise adds Zia AI and sandbox, and Ultimate adds advanced analytics and customization.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ca9138f2-35fd-49cf-8af2-819fa2691854', $q$Can Zoho CRM integrate with other tools?$q$, $q$Yes, Zoho CRM connects with more than 1,000 third-party applications, including Office 365 and Google Ads, through its marketplace and API.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ca9138f2-35fd-49cf-8af2-819fa2691854', $q$Does Zoho CRM support sales forecasting?$q$, $q$Yes, sales forecasting is included starting with the Standard plan and expands with more advanced reporting on higher tiers.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ca9138f2-35fd-49cf-8af2-819fa2691854', $q$Who is Zoho CRM best for?$q$, $q$Zoho CRM suits small businesses through large enterprises that want an affordable, customizable CRM that can scale as their sales processes grow.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ca9138f2-35fd-49cf-8af2-819fa2691854', $q$Does Zoho CRM offer a sandbox environment?$q$, $q$Yes, sandbox environments for testing changes before deployment are available starting with the Enterprise plan.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ca9138f2-35fd-49cf-8af2-819fa2691854', $q$Lead-to-deal sales pipeline management$q$, $q$Tracking leads through qualification, opportunity, and close using automated workflows and cadences.$q$, $q$Sales teams and sales operations$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ca9138f2-35fd-49cf-8af2-819fa2691854', $q$Multi-channel customer engagement$q$, $q$Managing customer conversations across email, chat, phone, and social channels in one unified record.$q$, $q$Customer-facing sales and support teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ca9138f2-35fd-49cf-8af2-819fa2691854', $q$Enterprise sales process standardization$q$, $q$Enforcing consistent, multi-step sales processes with blueprints, territory management, and approval rules.$q$, $q$Enterprise sales organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ca9138f2-35fd-49cf-8af2-819fa2691854', $q$Free$q$, $q$$0$q$, $q$monthly$q$, NULL, $q$["Up to 3 users","Leads and contacts management","Document management","Mobile apps"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ca9138f2-35fd-49cf-8af2-819fa2691854', $q$Standard$q$, $q$~$14/user/month billed annually$q$, $q$monthly or annual$q$, NULL, $q$["Bulk emails","Custom modules and workflows","Sales cadence","Sales forecasts","900+ marketplace extensions"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ca9138f2-35fd-49cf-8af2-819fa2691854', $q$Professional$q$, $q$~$23/user/month billed annually$q$, $q$monthly or annual$q$, NULL, $q$["Blueprint process automation","CPQ","Sales signals","Inventory management","Webhooks"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ca9138f2-35fd-49cf-8af2-819fa2691854', $q$Enterprise$q$, $q$~$40/user/month billed annually$q$, $q$monthly or annual$q$, NULL, $q$["Zia AI assistant","Territory management","Custom functions","Multi-user portals","Sandbox environment"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ca9138f2-35fd-49cf-8af2-819fa2691854', $q$Ultimate$q$, $q$~$52/user/month billed annually$q$, $q$monthly or annual$q$, NULL, $q$["Advanced analytics and data stories","Expanded customization limits","Data preparation tools","Advanced administration"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ca9138f2-35fd-49cf-8af2-819fa2691854', $q$overview$q$, $q$What Is Zoho CRM$q$, 2, ARRAY[$q$Zoho CRM is a sales and customer relationship management platform launched in 2005 to help businesses convert leads, manage customer relationships, and scale sales operations.$q$, $q$It is developed by Zoho Corporation, founded in 1996 and headquartered in Chennai, India, with a US headquarters in Austin, Texas, and roughly 24,000 employees worldwide.$q$, $q$Zoho CRM serves organizations of nearly every size, from freelancers using Zoho's lighter Bigin product up through enterprises running Zoho CRM's Ultimate plan with advanced customization and analytics.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ca9138f2-35fd-49cf-8af2-819fa2691854', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform provides sales automation through configurable workflows, sales cadences, and no-code customization, along with multi-channel communication tools that consolidate email, phone, chat, and social interactions into one customer view.$q$, $q$Zia, Zoho's AI assistant, supports tasks such as email rewriting, anomaly detection, and predictive insights, and Zoho CRM also integrates directly with ChatGPT for additional AI-assisted workflows.$q$, $q$Higher-tier plans add sales forecasting, territory management, blueprint-based process automation, CPQ tools for quoting, custom functions, and sandbox environments, while the platform connects with more than 1,000 third-party applications.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ca9138f2-35fd-49cf-8af2-819fa2691854', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Zoho CRM offers a free edition for up to three users with core lead management, document handling, and mobile app access.$q$, $q$Paid, per-user monthly plans billed annually start at roughly 14 dollars per user for Standard and scale up through Professional at roughly 23 dollars, Enterprise at roughly 40 dollars, and Ultimate at roughly 52 dollars per user per month, with each tier adding deeper automation, AI, and analytics capabilities.$q$, $q$Choosing monthly billing instead of annual billing raises the effective per-user price on every paid tier, and additional team-user seats are available as an add-on.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('74c8afcd-fff1-4116-8c21-aa7ea3ed5869', $q$Unified multi-channel inbox$q$, $q$Combines email, phone, chat, social, and messaging app conversations into one workspace.$q$, 0);
