INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('74c8afcd-fff1-4116-8c21-aa7ea3ed5869', $q$Workflow automation$q$, $q$Triggers actions automatically based on ticket events and conditions.$q$, 4);
