INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('74c8afcd-fff1-4116-8c21-aa7ea3ed5869', $q$Is Zoho Desk free?$q$, $q$Yes, Zoho Desk has a free plan that supports up to three agents with basic email ticket management.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('74c8afcd-fff1-4116-8c21-aa7ea3ed5869', $q$How much does Zoho Desk cost?$q$, $q$Paid plans billed annually range from roughly 7 dollars per agent per month for Express up to roughly 40 dollars per agent per month for Enterprise.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('74c8afcd-fff1-4116-8c21-aa7ea3ed5869', $q$Does Zoho Desk support live chat?$q$, $q$Yes, live chat is available starting with the Standard plan, and Enterprise adds Zoho SalesIQ integration for advanced chat features.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('74c8afcd-fff1-4116-8c21-aa7ea3ed5869', $q$What channels does Zoho Desk support?$q$, $q$Zoho Desk supports email, phone, live chat, social media, and messaging apps including WhatsApp, Instagram, Facebook, Telegram, WeChat, and Line.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('74c8afcd-fff1-4116-8c21-aa7ea3ed5869', $q$Does Zoho Desk have AI features?$q$, $q$Yes, Zoho Desk includes Zia, an AI assistant, an AI answer bot, and autonomous AI agents on the Enterprise plan.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('74c8afcd-fff1-4116-8c21-aa7ea3ed5869', $q$Can Zoho Desk handle multiple departments?$q$, $q$Yes, support for multiple departments is available starting with the Professional plan.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('74c8afcd-fff1-4116-8c21-aa7ea3ed5869', $q$How many companies use Zoho Desk?$q$, $q$Zoho Desk is used by more than 125,000 companies worldwide.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('74c8afcd-fff1-4116-8c21-aa7ea3ed5869', $q$Does Zoho Desk integrate with Zoho CRM?$q$, $q$Yes, Zoho Desk integrates with Zoho CRM and other Zoho products for a connected customer service and sales workflow.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('74c8afcd-fff1-4116-8c21-aa7ea3ed5869', $q$Multi-channel customer support$q$, $q$Managing support tickets from email, chat, phone, and social channels in one unified inbox.$q$, $q$Customer support teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('74c8afcd-fff1-4116-8c21-aa7ea3ed5869', $q$Self-service deflection$q$, $q$Reducing ticket volume through a searchable knowledge base, community forums, and AI chatbot.$q$, $q$Support and customer success teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('74c8afcd-fff1-4116-8c21-aa7ea3ed5869', $q$Enterprise support process automation$q$, $q$Standardizing complex support workflows across departments using Blueprint automation and SLA management.$q$, $q$Large support organizations and enterprises$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('74c8afcd-fff1-4116-8c21-aa7ea3ed5869', $q$Free$q$, $q$$0$q$, $q$n/a$q$, NULL, $q$["Up to 3 agents","Basic email ticket management","Contact management"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('74c8afcd-fff1-4116-8c21-aa7ea3ed5869', $q$Express$q$, $q$~$7/agent/month billed annually$q$, $q$monthly or annual$q$, NULL, $q$["Multi-channel email support","Social media integration","Web forms","Automatic ticket assignment","Custom domain"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('74c8afcd-fff1-4116-8c21-aa7ea3ed5869', $q$Standard$q$, $q$~$14/agent/month billed annually$q$, $q$monthly or annual$q$, NULL, $q$["Live chat widget","Instant messaging channels","Community forum","Generative AI capabilities","Knowledge base"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('74c8afcd-fff1-4116-8c21-aa7ea3ed5869', $q$Professional$q$, $q$~$23/agent/month billed annually$q$, $q$monthly or annual$q$, NULL, $q$["Telephony integration","Blueprint automation","Multiple departments","Round-robin assignment","Webhooks"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('74c8afcd-fff1-4116-8c21-aa7ea3ed5869', $q$Enterprise$q$, $q$~$40/agent/month billed annually$q$, $q$monthly or annual$q$, NULL, $q$["Autonomous AI agents","AI answer bot","Zia AI assistant","Multi-brand help center","Sandbox environment"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('74c8afcd-fff1-4116-8c21-aa7ea3ed5869', $q$overview$q$, $q$What Is Zoho Desk$q$, 2, ARRAY[$q$Zoho Desk is an AI-powered helpdesk platform launched in November 2016 by Zoho Corporation, built to unify customer support conversations across channels into one organized workspace.$q$, $q$Zoho Corporation was founded in 1996, is privately owned, and employs roughly 24,000 people globally, with headquarters in Chennai, India, and a US headquarters in Austin, Texas.$q$, $q$The platform is used by more than 125,000 companies and is positioned as an affordable, user-friendly alternative to larger helpdesk vendors like Zendesk and Freshdesk.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('74c8afcd-fff1-4116-8c21-aa7ea3ed5869', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Zoho Desk aggregates support conversations from email, phone, chat, social media, and messaging apps such as WhatsApp and Instagram into a single unified inbox, with intelligent ticket routing based on agent skill, workload, and availability.$q$, $q$A 24-hour self-service help center includes a searchable knowledge base, community forums, and an AI chatbot, while Zia, Zoho's AI assistant, handles routine tasks autonomously and hands off to human agents when needed.$q$, $q$Workflow automation, SLA management with automated escalations, and real-time analytics dashboards round out the platform, and higher plans add live chat, telephony integration, Blueprint process automation, and autonomous AI agents for resolving simple requests.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('74c8afcd-fff1-4116-8c21-aa7ea3ed5869', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Zoho Desk offers a free plan supporting up to three agents with basic email ticket management.$q$, $q$Paid, per-agent monthly plans billed annually start at roughly 7 dollars per agent for Express and scale up through Standard at roughly 14 dollars, Professional at roughly 23 dollars, and Enterprise at roughly 40 dollars per agent per month, with each tier unlocking more channels, automation, and AI capability.$q$, $q$Choosing monthly billing instead of an annual commitment raises the effective per-agent price on every paid plan.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dd3c3df9-d594-426d-bdb3-8cf09852fd57', $q$Drag-and-drop form builder$q$, $q$Create standard or card-style forms without any coding knowledge.$q$, 0);
