INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dd3c3df9-d594-426d-bdb3-8cf09852fd57', $q$Is Zoho Forms free?$q$, $q$Yes, Zoho Forms offers a free-forever plan for basic form creation and light usage.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dd3c3df9-d594-426d-bdb3-8cf09852fd57', $q$How much does Zoho Forms cost?$q$, $q$Paid plans range from 10 dollars per month for Basic up to 90 dollars per month for Premium, which adds HIPAA compliance.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dd3c3df9-d594-426d-bdb3-8cf09852fd57', $q$Does Zoho Forms support payment collection?$q$, $q$Yes, Zoho Forms integrates with PayPal, Stripe, and 2Checkout to collect payments directly through forms.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dd3c3df9-d594-426d-bdb3-8cf09852fd57', $q$Can Zoho Forms handle approval workflows?$q$, $q$Yes, multi-level approval workflows with conditional logic are available starting with the Standard plan.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dd3c3df9-d594-426d-bdb3-8cf09852fd57', $q$Does Zoho Forms work offline?$q$, $q$Yes, the Zoho Forms mobile app supports offline data collection with geolocation tagging and QR code scanning.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dd3c3df9-d594-426d-bdb3-8cf09852fd57', $q$Is Zoho Forms HIPAA compliant?$q$, $q$HIPAA compliance is available specifically on the Premium plan.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dd3c3df9-d594-426d-bdb3-8cf09852fd57', $q$What integrations does Zoho Forms support?$q$, $q$Zoho Forms integrates with more than 150 applications, including Salesforce, Google Sheets, and Microsoft Teams, plus other Zoho products.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dd3c3df9-d594-426d-bdb3-8cf09852fd57', $q$Who uses Zoho Forms?$q$, $q$Zoho Forms is used by more than 100,000 customers across industries including healthcare, education, e-commerce, construction, and nonprofits.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dd3c3df9-d594-426d-bdb3-8cf09852fd57', $q$Customer and lead data collection$q$, $q$Building forms to capture leads, customer feedback, or registration details and route them into a CRM or spreadsheet.$q$, $q$Marketing and sales teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dd3c3df9-d594-426d-bdb3-8cf09852fd57', $q$Internal approval workflows$q$, $q$Automating multi-step approval processes such as leave requests or purchase approvals using conditional logic.$q$, $q$HR and operations teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dd3c3df9-d594-426d-bdb3-8cf09852fd57', $q$Field and offline data collection$q$, $q$Gathering data on-site with geolocation tagging and QR code scanning, even without an internet connection.$q$, $q$Field teams, construction, and healthcare workers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('dd3c3df9-d594-426d-bdb3-8cf09852fd57', $q$Free$q$, $q$$0$q$, $q$n/a$q$, NULL, $q$["Basic form creation","Limited monthly submissions","Core form fields and sharing"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('dd3c3df9-d594-426d-bdb3-8cf09852fd57', $q$Basic$q$, $q$$10$q$, $q$monthly$q$, NULL, $q$["Unlimited forms","10,000 monthly submissions","PayPal, Stripe, and 2Checkout payment integrations","Custom themes","500 MB storage"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('dd3c3df9-d594-426d-bdb3-8cf09852fd57', $q$Standard$q$, $q$$25$q$, $q$monthly$q$, NULL, $q$["Multi-user access","Approval workflows","Higher submission limits"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('dd3c3df9-d594-426d-bdb3-8cf09852fd57', $q$Professional$q$, $q$$50$q$, $q$monthly$q$, NULL, $q$["Higher submission volumes","Advanced workflow automation","Expanded integrations"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('dd3c3df9-d594-426d-bdb3-8cf09852fd57', $q$Premium$q$, $q$$90$q$, $q$monthly$q$, NULL, $q$["HIPAA compliance","Highest submission limits","Advanced security and compliance features"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dd3c3df9-d594-426d-bdb3-8cf09852fd57', $q$overview$q$, $q$What Is Zoho Forms$q$, 2, ARRAY[$q$Zoho Forms is a no-code online form builder, launched in August 2014, that lets users create, distribute, and manage data collection forms without writing any code.$q$, $q$It is developed by Zoho Corporation, founded in 1996 and headquartered in Chennai, India, with a US headquarters in Austin, Texas, and roughly 24,000 employees worldwide.$q$, $q$The platform reports more than 100,000 customers and over 554,000 forms created, spanning industries from healthcare and education to construction and e-commerce.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dd3c3df9-d594-426d-bdb3-8cf09852fd57', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Zoho Forms provides a drag-and-drop builder for standard multi-field forms or card-style forms with one question per page, along with customizable themes, colors, fonts, and branding, and forms can be shared via email, social media, or website embed.$q$, $q$Workflow automation with conditional logic and multi-level approvals extends Zoho Forms beyond simple surveys into internal processes like leave requests or purchase approvals, while real-time notifications alert teams to new submissions instantly.$q$, $q$The mobile app supports offline data collection with geolocation tagging and QR code scanning, and the platform integrates with more than 150 applications, including Salesforce, Google Sheets, and Microsoft Teams, with security features covering SSL encryption, data encryption at rest, and GDPR, HIPAA, and CCPA compliance support.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dd3c3df9-d594-426d-bdb3-8cf09852fd57', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Zoho Forms offers a free-forever plan for basic form creation and light usage.$q$, $q$Paid monthly plans include Basic at 10 dollars per month with unlimited forms and 10,000 monthly submissions, Standard at 25 dollars per month adding multi-user access and approval workflows, Professional at 50 dollars per month for higher submission volumes, and Premium at 90 dollars per month, which adds HIPAA compliance.$q$, $q$Pricing scales primarily with submission volume, number of users, and compliance requirements rather than the number of forms created.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('dd3c3df9-d594-426d-bdb3-8cf09852fd57', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
